INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (387,6,'leadership_0_bio','For the past two decades, Paul has helped leading companies in a wide range of enthusiast industries develop strategic design and integrated brand communication programs. In all cases, his work has had a positive and measurable impact on his clients\' business performance. Tennis, running, Red Sox enthusiast paul@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (388,6,'_leadership_0_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (389,6,'leadership_1_bio','As creative director and enthusiast-branding expert, Doreen works in close collaboration with brand partners to develop targeted branding and identity solutions that motivate enthusiasts to take action. Her work has been consistently recognized in national and international design publications including Graphis, Communication Arts, Print and HOW. Dark Chocolate, urban dwelling + dog enthusiast doreen@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (390,6,'_leadership_1_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (391,6,'leadership_2_bio','Christine brings a unique blend of design, production and client service skills and expertise to her role at Saltworks. Her brand-building portfolio spans a broad range of enthusiast organizations that include the Phoenix Coyotes Hockey Club, Backroads Active Travel, Boyd Gaming and Ballet Arizona. Running, yoga, Charity Miles enthusiast christine@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (392,6,'_leadership_2_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (393,6,'leadership_3_bio','Carlos has more than 25 years of experience developing integrated branding, interactive, and social programs for enthusiast audiences. He works closely with project teams throughout the different phases of each engagement to ensure that design, content and technical development align with both client and user goals. Wine, music, travel enthusiast carlos@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (394,6,'_leadership_3_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (395,6,'leadership_4_bio','Drake enables brands to achieve sustainable differentiation by proactively empowering customers. By developing strategic alignment between brand, customer experience, and product development, he can turn what is often a zero-sum game (A or B) into a win-win situation (A and B). Bushido, exploration, and wildlife enthusiast drake@saltworksinc.com');
