INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (603,47,'leadership_0_bio','For the past two decades, Paul has helped leading companies in a wide range of enthusiast industries develop strategic design and integrated brand communication programs. In all cases, his work has had a positive and measurable impact on his clients\' business performance.\r\n\r\nTennis, running, Red Sox enthusiast\r\n\r\npaul@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (604,47,'_leadership_0_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (605,47,'leadership_1_name','Doreen Caldera');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (606,47,'_leadership_1_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (607,47,'leadership_1_title','Brand Design; Cofounder');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (608,47,'_leadership_1_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (609,47,'leadership_1_image','44');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (610,47,'_leadership_1_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (611,47,'leadership_1_bio','As creative director and enthusiast-branding expert, Doreen works in close collaboration with brand partners to develop targeted branding and identity solutions that motivate enthusiasts to take action. Her work has been consistently recognized in national and international design publications including Graphis, Communication Arts, Print and HOW.\r\n\r\nDark Chocolate, urban dwelling + dog enthusiast\r\n\r\ndoreen@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (612,47,'_leadership_1_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (613,47,'leadership_2_name','Frances Wu');
