INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (942,91,'leadership_0_image','46');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (943,91,'_leadership_0_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (944,91,'leadership_0_bio','For the past two decades, Paul has helped leading companies in a wide range of enthusiast industries develop strategic design and integrated brand communication programs. In all cases, his work has had a positive and measurable impact on his clients\' business performance.\r\n\r\nTennis, running, Red Sox enthusiast\r\n\r\npaul@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (945,91,'_leadership_0_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (946,91,'leadership_1_name','Doreen Caldera');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (947,91,'_leadership_1_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (948,91,'leadership_1_title','Brand Design; Cofounder');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (949,91,'_leadership_1_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (950,91,'leadership_1_image','44');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (951,91,'_leadership_1_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (952,91,'leadership_1_bio','As creative director and enthusiast-branding expert, Doreen works in close collaboration with brand partners to develop targeted branding and identity solutions that motivate enthusiasts to take action. Her work has been consistently recognized in national and international design publications including Graphis, Communication Arts, Print and HOW.\r\n\r\nDark Chocolate, urban dwelling + dog enthusiast\r\n\r\ndoreen@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (953,91,'_leadership_1_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (954,91,'leadership_2_name','Frances Wu');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (955,91,'_leadership_2_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (956,91,'leadership_2_title','Brand Strategy');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (957,91,'_leadership_2_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (958,91,'leadership_2_image','45');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (959,91,'_leadership_2_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (960,91,'leadership_2_bio','Frances\' passion is to discover the subtleties that influence audiences and leverage that knowledge in marketing content. She balances analysis with visceral perspective to reveal behavioral insights that draw customers to a wide range of enthusiast brands across multiple media.  \r\n\r\nCookware + cutlery enthusiast\r\n\r\nfrances@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (961,91,'_leadership_2_bio','field_54e2215883148');
