INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1339,95,'_clients','field_54e216e8cac2c');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1340,95,'services_lede','Saltworks helps organizations that engage enthusiast audiences create and control their future. We support organizations across their core marketing mandates: understanding enthusiast customers and competitors, defining business, brand and product strategies, executing marketing programs and managing customers for the greatest value. We build upon your existing resources and cost-effectively fill in the blanks where necessary.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1341,95,'_services_lede','field_54e21759cac33');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1342,95,'services_0_title','Enthusiast Brand Assessment');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1343,95,'_services_0_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1344,95,'services_0_description','Who are your enthusiasts, and what are you doing to engage them? What are your biggest threats and greatest opportunities? Saltworks starts with an initial audit of your brand, including an honest critique of how your existing design approach and communication strategy stacks up against the expectations of your most valuable customers.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1345,95,'_services_0_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1346,95,'services_1_title','Enthusiast Brand Articulation');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1347,95,'_services_1_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1348,95,'services_1_description','Saltworks helps enthusiast brand organizations thrive in competitive environments. Using existing client data and collecting additional data as necessary, we develop insights that include a deep and nuanced understanding of customer behavior and needs, market segments and demand trends. We apply those insights to the content development and design of key tactics. The result is an executional road map for the balance of your integrated marketing program.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1349,95,'_services_1_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1350,95,'services_2_title','Enthusiast Brand Build');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1351,95,'_services_2_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1352,95,'services_2_description','Once Saltworks helps companies define their message and build a compelling and relevant story around it, we execute integrated marketing communications programs that ensure a  company is communicating the right message, to the right customer, at the right time, using the right tools. In the end, we answer the customer\'s question: \"Why should I buy from you?');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (1353,95,'_services_2_description','field_54e21742cac32');
