INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (2990,277,'leadership_1_bio','As creative director and enthusiast-branding expert, Doreen works in close collaboration with brand partners to develop targeted branding and identity solutions that motivate enthusiasts to take action. Her work has been consistently recognized in national and international design publications including Graphis, Communication Arts, Print and HOW.\r\n\r\nDark Chocolate, urban dwelling + dog enthusiast\r\n\r\ndoreen@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (2991,277,'_leadership_1_bio','field_54e2215883148');
