INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3354,278,'leadership_2_bio','Frances\' passion is to discover the subtleties that influence audiences and leverage that knowledge in marketing content. She balances analysis with visceral perspective to reveal behavioral insights that draw customers to a wide range of enthusiast brands across multiple media. \r\n\r\nCookware + cutlery enthusiast\r\n\r\nfrances@saltworksinc.com');
