INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3671,281,'_clients','field_54e216e8cac2c');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3672,281,'services_lede','Saltworks helps organizations that engage enthusiast audiences create and control their future. We support organizations across their core marketing mandates: understanding enthusiast customers and competitors, defining business, brand and product strategies, executing marketing programs and managing customers for the greatest value. We build upon your existing resources and cost-effectively fill in the blanks where necessary.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3673,281,'_services_lede','field_54e21759cac33');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3674,281,'services_0_title','Enthusiast Brand Assessment');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3675,281,'_services_0_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3676,281,'services_0_description','Who are your enthusiasts, and what are you doing to engage them? What are your biggest threats and greatest opportunities? Saltworks starts with an initial audit of your brand, including an honest critique of how your existing design approach and communication strategy stacks up against the expectations of your most valuable customers.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3677,281,'_services_0_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3678,281,'services_1_title','Enthusiast Brand Articulation');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3679,281,'_services_1_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3680,281,'services_1_description','Saltworks helps enthusiast brand organizations thrive in competitive environments. Using existing client data and collecting additional data as necessary, we develop insights that include a deep and nuanced understanding of customer behavior and needs, market segments and demand trends. We apply those insights to the content development and design of key tactics. The result is an executional road map for the balance of your integrated marketing program.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3681,281,'_services_1_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3682,281,'services_2_title','Enthusiast Brand Build');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3683,281,'_services_2_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3684,281,'services_2_description','Once Saltworks helps companies define their message and build a compelling and relevant story around it, we execute integrated marketing communications programs that ensure a  company is communicating the right message, to the right customer, at the right time, using the right tools. In the end, we answer the customer\'s question: \"Why should I buy from you?');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3685,281,'_services_2_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3686,281,'services','3');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3687,281,'_services','field_54e21727cac30');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3688,281,'leadership_0_name','Paul Caldera');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3689,281,'_leadership_0_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3690,281,'leadership_0_title','Brand Integration; Cofounder');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3691,281,'_leadership_0_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3692,281,'leadership_0_image','46');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3693,281,'_leadership_0_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3694,281,'leadership_0_bio','For the past two decades, Paul has helped leading companies in a wide range of enthusiast industries develop strategic design and integrated brand communication programs. In all cases, his work has had a positive and measurable impact on his clients\' business performance.\r\n\r\nTennis, running, Red Sox enthusiast\r\n\r\npaul@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3695,281,'_leadership_0_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3696,281,'leadership_1_name','Doreen Caldera');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3697,281,'_leadership_1_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3698,281,'leadership_1_title','Brand Design; Cofounder');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3699,281,'_leadership_1_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3700,281,'leadership_1_image','44');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3701,281,'_leadership_1_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3702,281,'leadership_1_bio','As creative director and enthusiast-branding expert, Doreen works in close collaboration with brand partners to develop targeted branding and identity solutions that motivate enthusiasts to take action. Her work has been consistently recognized in national and international design publications including Graphis, Communication Arts, Print and HOW.\r\n\r\nDark Chocolate, urban dwelling + dog enthusiast\r\n\r\ndoreen@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3703,281,'_leadership_1_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3704,281,'leadership_2_name','Frances Wu');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3705,281,'_leadership_2_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3706,281,'leadership_2_title','Brand Strategy');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3707,281,'_leadership_2_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3708,281,'leadership_2_image','45');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3709,281,'_leadership_2_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3710,281,'leadership_2_bio','Frances\' passion is to discover the subtleties that influence audiences and leverage that knowledge in marketing content. She balances analysis with visceral perspective to reveal behavioral insights that draw customers to a wide range of enthusiast brands across multiple media. \r\n\r\nCookware + cutlery enthusiast\r\n\r\nfrances@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3711,281,'_leadership_2_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (3712,281,'leadership_3_name','Christine Bailey');
