INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (7643,294,'leadership_4_bio','Carlos has more than 25 years of experience developing integrated branding, interactive, and social programs for enthusiast audiences. He works closely with project teams throughout the different phases of each engagement to ensure that design, content and technical development align with both client and user goals.\r\n\r\nWine, music, travel enthusiast\r\n\r\ncarlos@saltworksinc.com');
