INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (8347,297,'_leadership_3_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (8348,297,'leadership_3_bio','Christine brings a unique blend of design, production and client service skills and expertise to her role at Saltworks. Her brand-building portfolio spans a broad range of enthusiast organizations that include the Phoenix Coyotes Hockey Club, Backroads Active Travel, Boyd Gaming and Ballet Arizona.\r\n\r\nRunning, yoga, Charity Miles enthusiast\r\n\r\nchristine@saltworksinc.com');
