INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10099,302,'_leadership_0_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10100,302,'leadership_0_title','Brand Integration; Cofounder');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10101,302,'_leadership_0_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10102,302,'leadership_0_image','46');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10103,302,'_leadership_0_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10104,302,'leadership_0_bio','For the past two decades, Paul has helped leading companies in a wide range of enthusiast industries develop strategic design and integrated brand communication programs. In all cases, his work has had a positive and measurable impact on his clients\' business performance.\r\n\r\nTennis, running, Red Sox enthusiast\r\n\r\npaul@saltworksinc.com');
