INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10472,303,'leadership_2_title','Brand Strategy');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10473,303,'_leadership_2_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10474,303,'leadership_2_image','45');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10475,303,'_leadership_2_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10476,303,'leadership_2_bio','Frances\' passion is to discover the subtleties that influence audiences and leverage that knowledge in marketing content. She balances analysis with visceral perspective to reveal behavioral insights that draw customers to a wide range of enthusiast brands across multiple media. \r\n\r\nCookware + cutlery enthusiast\r\n\r\nfrances@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (10477,303,'_leadership_2_bio','field_54e2215883148');
