INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11533,311,'_clients','field_54e216e8cac2c');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11534,311,'services_lede','Saltworks helps organizations that engage enthusiast audiences create and control their future. We support organizations across their core marketing mandates: understanding enthusiast customers and competitors, defining business, brand and product strategies, executing marketing programs and managing customers for the greatest value. We build upon your existing resources and cost-effectively fill in the blanks where necessary.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11535,311,'_services_lede','field_54e21759cac33');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11536,311,'services_0_title','Enthusiast Brand Assessment');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11537,311,'_services_0_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11538,311,'services_0_description','Who are your enthusiasts, and what are you doing to engage them? What are your biggest threats and greatest opportunities? Saltworks starts with an initial audit of your brand, including an honest critique of how your existing design approach and communication strategy stacks up against the expectations of your most valuable customers.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11539,311,'_services_0_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11540,311,'services_1_title','Enthusiast Brand Articulation');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11541,311,'_services_1_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11542,311,'services_1_description','Saltworks helps enthusiast brand organizations thrive in competitive environments. Using existing client data and collecting additional data as necessary, we develop insights that include a deep and nuanced understanding of customer behavior and needs, market segments and demand trends. We apply those insights to the content development and design of key tactics. The result is an executional road map for the balance of your integrated marketing program.');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11543,311,'_services_1_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11544,311,'services_2_title','Enthusiast Brand Build');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11545,311,'_services_2_title','field_54e21736cac31');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11546,311,'services_2_description','Once Saltworks helps companies define their message and build a compelling and relevant story around it, we execute integrated marketing communications programs that ensure a  company is communicating the right message, to the right customer, at the right time, using the right tools. In the end, we answer the customer\'s question: \"Why should I buy from you?');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11547,311,'_services_2_description','field_54e21742cac32');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11548,311,'services','3');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11549,311,'_services','field_54e21727cac30');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11550,311,'leadership_0_name','Paul Caldera');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11551,311,'_leadership_0_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11552,311,'leadership_0_title','Brand Integration; Cofounder');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11553,311,'_leadership_0_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11554,311,'leadership_0_image','46');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11555,311,'_leadership_0_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11556,311,'leadership_0_bio','For the past two decades, Paul has helped leading companies in a wide range of enthusiast industries develop strategic design and integrated brand communication programs. In all cases, his work has had a positive and measurable impact on his clients\' business performance.\r\n\r\nTennis, running, Red Sox enthusiast\r\n\r\npaul@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11557,311,'_leadership_0_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11558,311,'leadership_1_name','Doreen Caldera');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11559,311,'_leadership_1_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11560,311,'leadership_1_title','Brand Design; Cofounder');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11561,311,'_leadership_1_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11562,311,'leadership_1_image','44');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11563,311,'_leadership_1_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11564,311,'leadership_1_bio','As creative director and enthusiast-branding expert, Doreen works in close collaboration with brand partners to develop targeted branding and identity solutions that motivate enthusiasts to take action. Her work has been consistently recognized in national and international design publications including Graphis, Communication Arts, Print and HOW.\r\n\r\nDark Chocolate, urban dwelling + dog enthusiast\r\n\r\ndoreen@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11565,311,'_leadership_1_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11566,311,'leadership_2_name','Christine Bailey');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11567,311,'_leadership_2_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11568,311,'leadership_2_title','Brand Build');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11569,311,'_leadership_2_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11570,311,'leadership_2_image','43');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11571,311,'_leadership_2_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11572,311,'leadership_2_bio','Christine brings a unique blend of design, production and client service skills and expertise to her role at Saltworks. Her brand-building portfolio spans a broad range of enthusiast organizations that include the Phoenix Coyotes Hockey Club, Backroads Active Travel, Boyd Gaming and Ballet Arizona.\r\n\r\nRunning, yoga, Charity Miles enthusiast\r\n\r\nchristine@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11573,311,'_leadership_2_bio','field_54e2215883148');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11574,311,'leadership_3_name','Carlos Alcala');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11575,311,'_leadership_3_name','field_54e218533d3cb');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11576,311,'leadership_3_title','Brand Interactive');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11577,311,'_leadership_3_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11578,311,'leadership_3_image','42');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11579,311,'_leadership_3_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11580,311,'leadership_3_bio','Carlos has more than 25 years of experience developing integrated branding, interactive, and social programs for enthusiast audiences. He works closely with project teams throughout the different phases of each engagement to ensure that design, content and technical development align with both client and user goals.\r\n\r\nWine, music, travel enthusiast\r\n\r\ncarlos@saltworksinc.com');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11581,311,'_leadership_3_bio','field_54e2215883148');
