INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11585,311,'_leadership_4_title','field_54e2185e3d3cc');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11586,311,'leadership_4_image','305');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11587,311,'_leadership_4_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11588,311,'leadership_4_bio','Drake enables brands to achieve sustainable differentiation by proactively empowering customers. By developing strategic alignment between brand, customer experience, and product development, Drake can turn what is often a zero-sum game (A or B) into a win-win situation (A and B).\r\n\r\nBushido, exploration, and wildlife enthusiast');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11589,311,'_leadership_4_bio','field_54e2215883148');
