INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11596,311,'leadership_5_bio','Katie has a strong foundation anchored in ethnographic research and product innovation. Her superpowers include the ability to translate data from qualitative research into effective tools for design and sift through complex information to quickly present a clear and concise point of view.\r\n\r\nGardening, cooking and painting enthusiast');
