INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11951,312,'_leadership_4_image','field_54e218643d3cd');
INSERT INTO `SERVMASK_PREFIX_postmeta` VALUES (11952,312,'leadership_4_bio','Drake enables brands to achieve sustainable differentiation by proactively empowering customers. By developing strategic alignment between brand, customer experience, and product development, he can turn what is often a zero-sum game (A or B) into a win-win situation (A and B).\r\n\r\nBushido, exploration, and wildlife enthusiast');
