INSERT INTO `SERVMASK_PREFIX_posts` VALUES (1,1,'2015-02-16 15:39:59','2015-02-16 15:39:59','Welcome to WordPress. This is your first post. Edit or delete it, then start blogging!','Hello world!','','publish','open','open','','hello-world','','','2015-02-16 15:39:59','2015-02-16 15:39:59','',0,'https://saltworksinc.com/?p=1',0,'post','',1);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (6,1,'2015-02-16 16:02:35','2015-02-16 16:02:35','Brand enthusiasts aren’t just customers. They’re discerning buyers who feel compelled to express their values, look for substance, and do their homework on purchases and relationships. And once they find brands they love, they become loyalists—and ambassadors.\n\n<strong style=\"line-height: 1.5;\">Saltworks is a branding and experience design firm where enthusiast brands find their following.</strong>\n<p class=\"p1\"><span class=\"s1\">Since 1995, Saltworks has provided brand positioning, growth marketing, and experience design solutions that target high consideration and high emotion customers. We’ve helped brands acquire and retain market share in industries ranging from—</span><span class=\"s1\">aviation and boating to outdoor, music, consumer electronics, adventure + educational travel, sporting goods, medical products + services, private + higher education, pharma and financial services.</span></p>','Saltworks Enthusiast Branding','','publish','open','open','','home-page','','','2024-07-15 10:24:42','2024-07-15 14:24:42','',0,'https://saltworksinc.com/?page_id=6',0,'page','',0);
INSERT INTO `SERVMASK_PREFIX_posts` VALUES (7,1,'2015-02-16 16:02:35','2015-02-16 16:02:35','Brand enthusiasts aren’t just customers. They’re discerning buyers who feel compelled to express their lifestyle, demand substance, and do their homework on the things they choose to buy. And once they find brands they love, they become loyalists—and ambassadors.\r\n\r\n<strong>Saltworks is a branding and design firm where enthusiast brands find their following.</strong>\r\n\r\nSince 1984, saltworks has partnered with purveyors of luxury goods, outdoor adventures, high-performance gear and exclusive experiences to engage and mobilize the enthusiasts who live and breathe their brands. And, as different as their offerings may be, saltworks intensifies the essence that makes each brand legendary.\r\n','Home Page','','inherit','open','open','','6-revision-v1','','','2015-02-16 16:02:35','2015-02-16 16:02:35','',6,'https://saltworksinc.com/?p=7',0,'revision','',0);
