INSERT INTO `SERVMASK_PREFIX_posts` VALUES (348,2,'2020-12-14 15:16:50','2020-12-14 20:16:50','Brand enthusiasts aren’t just customers. They’re discerning buyers who feel compelled to express their values, look for substance, and do their homework on purchases and relationships. And once they find brands they love, they become loyalists—and ambassadors.\n\n<strong style=\"line-height: 1.5;\">Saltworks is a branding and experience design firm where enthusiast brands find their following.</strong>\n<p class=\"p1\"><span class=\"s1\">Since 1995, Saltworks has provided brand positioning, growth marketing, and experience design solutions that target high consideration and high emotion customers. We’ve helped brands acquire and retain market share in industries ranging from aviation and boating to outdoor, adventure travel, healthcare, medical products, pharma, education, financial services, consumer electronics, music, and sporting goods.</span></p>','Saltworks Enthusiast Branding','','inherit','closed','closed','','6-revision-v1','','','2020-12-14 15:16:50','2020-12-14 20:16:50','',6,'https://saltworksinc.com/2020/12/6-revision-v1/',0,'revision','',0);
